const CLINIC_ID = '6a718c1d-9a79-4e80-ad71-1c5c8a2ea190';

// Leads que não agendaram e último contato há mais de 1 dia
const umDiaAtras = new Date();
umDiaAtras.setDate(umDiaAtras.getDate() - 1);

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/leads?clinic_id=eq.${CLINIC_ID}&status=eq.contacted&last_contact_at=lt.${umDiaAtras.toISOString()}`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
});

// Filtrar: máximo 3 follow-ups
const leads = (response || []).filter(lead => {
  const notas = lead.notes || '';
  const followups = (notas.match(/FOLLOW-UP/g) || []).length;
  return followups < 3;
});

if (leads.length === 0) {
  return [{ json: { semLeads: true, mensagem: 'Nenhum lead para follow-up hoje' } }];
}

return leads.map(lead => ({ json: lead }));

const SUPABASE_URL = 'https://yqrjbyaucimvmzpfipgs.supabase.co';
