const lead = $input.item.json;

const historico = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/eva_conversations?phone=eq.${lead.phone}&order=created_at.desc&limit=5`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
