  json: {
    ...lead,
    historico: contexto
  }
}];

const SUPABASE_URL = 'https://yqrjbyaucimvmzpfipgs.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InlxcmpieWF1Y2ltdm16cGZpcGdzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NTc3MTQ4NywiZXhwIjoyMDkxMzQ3NDg3fQ.q4VwAwLbPQTXGCdW1ZfLvmyW8TAQuJ67LgI3gCO6mzg';

const lead = $('Buscar Histórico').item.json;
const mensagem = $('Gerar Follow-up').item.json.message?.content || $('Gerar Follow-up').item.json.text || '';
const dataAtual = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

// Atualizar notas do lead com registro do follow-up
const notasAtuais = lead.notes || '';
const novasNotas = `📤 FOLLOW-UP ${dataAtual}:\n${mensagem}\n\n${notasAtuais}`;

await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/leads?id=eq.${lead.id}`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
  body: { notes: novasNotas, last_contact_at: new Date().toISOString() }
});

// Salvar na conversa
await this.helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/eva_conversations`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
  body: { phone: lead.phone, assistant_message: `[FOLLOW-UP] ${mensagem}` }
});

